#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

/**
 * @brief 计算使数组变为非递减所需所有操作中，所选 x 的值之和可能达到的最小值。
 * 
 * @param nums 长度为 n 的整数数组。
 * @return Int64 返回最小总和。
 */
int64_t solve(const vector<int64_t>& nums) {
    int n = nums.size();
    if (n <= 1) {
        return 0;
    }

    int64_t total_sum_x = 0;

    // 我们关注相邻元素 nums[i] 和 nums[i+1]。
    // 为了使数组非递减，我们必须保证最终的 nums'[i] <= nums'[i+1]。
    // 每次操作增加的 x 是一个正整数。
    // 考虑一对相邻元素 nums[i] 和 nums[i+1]。
    // 如果 nums[i] > nums[i+1]，那么至少需要对 nums[i+1] 施加的操作比对 nums[i] 施加的操作多，
    // 或者对 nums[i] 施加的操作比对 nums[i+1] 施加的操作少，以满足最终的条件。

    // 关键洞察：
    // 假设我们对所有元素施加了总的增量 S_i (其中 S_i 是由所有操作决定的，S_i >= 0)。
    // 最终数组为 nums'[i] = nums[i] + S_i。
    // 我们要求 nums[i] + S_i <= nums[i+1] + S_{i+1}，即 S_{i+1} - S_i >= nums[i] - nums[i+1]。
    // 目标是最小化所有操作中使用的 x 的总和。
    // 设总操作次数为 K，第 j 次操作增加的量为 x_j，作用于子数组 [l_j, r_j]。
    // S_i = sum(x_j for all j where l_j <= i <= r_j).
    // 我们要求最小化 sum(x_j).

    // 考虑差值：d_i = nums[i] - nums[i+1]。
    // 如果 d_i <= 0 (即 nums[i] <= nums[i+1])，则我们不需要额外的操作来满足这个局部条件，S_{i+1} - S_i >= d_i 自动满足如果 S_{i+1} >= S_i。
    // 如果 d_i > 0 (即 nums[i] > nums[i+1])，我们至少需要 S_{i+1} - S_i >= d_i。

    // 为了最小化总和，我们应该尽可能让增量 S_i 增加得少，并且尽量让 S_{i+1} - S_i 的差值刚好达到 d_i 的需求。

    // 我们可以维护一个“当前需要保证的最低增量”的累计值。
    // 设 D_i = max(0, nums[i] - nums[i+1])。这是我们至少需要让 S_{i+1} - S_i >= D_i 的要求。
    // 设 C_i 是我们希望达成的 S_i 的值（不是绝对值，而是相对于 S_0 的偏移量）。

    // 最优解的结构是：存在一个基准增量 S_0，使得 S_i = S_0 + \sum_{j=0}^{i-1} \max(0, nums[j] - nums[j+1]) + \text{some adjustment}_i。
    // 但是，我们只需要关注相邻元素的要求。

    // 设 B_i 是一个“累积的需要被弥补的差距”。
    // B_0 = 0.
    // 对于 i = 0 to n-2:
    //   如果 nums[i] > nums[i+1]:
    //     差距 = nums[i] - nums[i+1]
    //     这个差距必须通过操作来弥补，使得最终 nums'[i] <= nums'[i+1]。
    //     由于我们希望最小化总和，我们希望这个弥补是局部且最小的。
    //     一个操作增加 x 作用于子数组 [l, r]。
    //     如果 l <= i < i+1 <= r, 两个元素都增加 x，差值不变。
    //     如果 i < l <= r, nums'[i] 不变，nums'[i+1] 增加 x，差值减小 x。
    //     如果 l <= i <= r < i+1, nums'[i] 增加 x，nums'[i+1] 不变，差值增大 x。

    // 考虑差值 d_i = nums[i] - nums[i+1] > 0。
    // 我们需要 S_{i+1} - S_i >= d_i。
    // 最小化总和意味着我们应该让 S_i 尽可能小。
    // 设 S_i = S_i^min。
    // S_0^min = 0 (因为我们可以认为所有操作都从某个基准开始，我们只关心相对变化)。
    // S_1^min = max(0, S_0^min + d_0)
    // S_2^min = max(0, S_1^min + d_1)  <- 这里的 d_1 是 nums[1] - nums[2]
    // 实际上，我们希望 S_{i+1} >= S_i + (nums[i] - nums[i+1])。
    // 因此，我们必须有 S_{i+1} >= max(S_i + nums[i] - nums[i+1], 0) ? 
    // 不对，S_i 和 S_{i+1} 都是非负的。

    // 正确的最小化构造：
    // 设 S_0 = 0.
    // 对于 i = 0 to n-2:
    //   如果 nums[i] > nums[i+1]:
    //     我们必须增加 S_{i+1} 相对于 S_i 的值至少为 nums[i] - nums[i+1]。
    //     设需要的增量为 req = nums[i] - nums[i+1]。
    //     我们更新 S_{i+1} 使得 S_{i+1} >= S_i + req。
    //     但更简单地看，我们累积需要的差值。

    // 设累积差值 C = 0.
    // 对于 i = 0 to n-2:
    //   C += nums[i] - nums[i+1]
    //   如果 C > 0，说明到目前为止，我们需要一个总增量至少达到 C。
    //   这个 C 实际上是 S_i - S_0 的最小要求。

    // 考虑总和。每个操作的 x 都会贡献到总和中。
    // 假设我们只需要保证 S_{i+1} - S_i >= max(0, nums[i] - nums[i+1])。
    // 设 R_i = max(0LL, nums[i] - nums[i+1]).
    // 我们需要 S_{i+1} >= S_i + R_i。
    // 最小化 S_{n-1} 意味着我们应该让 S_i 尽可能小。
    // 最小 S_{n-1} = sum_{i=0}^{n-2} R_i.

    // 这个最小总和 S_{n-1} (如果 S_0=0) 恰好等于所有必需的局部差值之和，因为我们可以通过一个作用于 [i+1, n-1] 的操作来满足 R_i。
    // 例如，如果 R_i = 5，我们对子数组 [i+1, n-1] 增加 5。
    // 此时 S_{i+1} 增加了 5，S_i 不变，满足 S_{i+1} - S_i >= 5。
    // 总和是 sum(R_i)。

    for (int i = 0; i < n - 1; ++i) {
        if (nums[i] > nums[i+1]) {
            // 必须弥补的差值
            int64_t diff = nums[i] - nums[i+1];
            total_sum_x += diff;
        }
    }

    return total_sum_x;
}
