 */
int64_t solve(std::vector<int64_t> nums) {
    int n = nums.size();
    if (n <= 1) {
        return 0;
    }

    int64_t total_x_sum = 0;

    // 只需要关注相邻元素不满足 nums[i] <= nums[i+1] 的情况。
    // 当 nums[i] > nums[i+1] 时，我们需要增加一个至少为 nums[i] - nums[i+1] 的量到 nums[i+1] 及其后续元素。
    // 由于我们可以选择任意子数组，一个关键的观察是：
    // 为了满足 nums'[i] <= nums'[i+1] (其中 ' denotes after operations),
    // 如果 nums[i] > nums[i+1]，我们需要增加一个值 x_i 使得 nums[i] + A_i <= nums[i+1] + B_i，
